<script>document.addEventListener('DOMContentLoaded',function(){var form=document.querySelector('[data-settings-form]');if(!form)return;var tabs=form.querySelectorAll('[data-tab]');var panels=form.querySelectorAll('[data-panel]');tabs.forEach(function(tab){tab.addEventListener('click',function(){tabs.forEach(function(t){t.classList.remove('active')});panels.forEach(function(p){p.classList.remove('active')});tab.classList.add('active');form.querySelector('[data-panel="'+tab.dataset.tab+'"]').classList.add('active');});});form.querySelectorAll('[data-image-input]').forEach(function(input){input.addEventListener('change',function(){var file=input.files[0];var summary=form.querySelector('[data-validation-summary]');if(!file)return;if(!file.type.startsWith('image/')||file.size>2*1024*1024){summary.style.display='block';summary.innerHTML='<div>الصورة يجب أن تكون ملف صورة وحجمها لا يتجاوز 2MB.</div>';input.value='';return;}var img=document.getElementById(input.dataset.preview);if(img)img.src=URL.createObjectURL(file);summary.style.display='none';});});form.addEventListener('submit',function(event){var errors=[];var currency=form.querySelector('[name="settings[default_currency]"]');if(currency&& !/^[A-Za-z]{3}$/.test(currency.value.trim()))errors.push('العملة الافتراضية يجب أن تكون رمزاً من 3 أحرف مثل JOD.');if(errors.length){event.preventDefault();var summary=form.querySelector('[data-validation-summary]');summary.style.display='block';summary.innerHTML=errors.map(function(e){return '<div>'+e+'</div>';}).join('');window.scrollTo({top:form.offsetTop-20,behavior:'smooth'});}});});</script>
